const kwString = $.input.keywords || '';
const keywords = kwString.split(',').map(k => k.trim()).filter(k => k.length > 0);
return { keywords, keywordCount: keywords.length };

const keywords = $.steps.parseKeywords.output.keywords;
const iterations = $.steps.searchKeywords.response.iterations || [];
let compiled = '';

keywords.forEach((kw, i) => {
  const iter = iterations[i];
  const results = (iter && iter.searchKeyword && iter.searchKeyword.response && iter.searchKeyword.response.results) ? iter.searchKeyword.response.results : [];
  compiled += '=== KEYWORD: "' + kw + '" (' + results.length + ' results) ===\n';
  results.forEach((r, j) => {
    compiled += (j + 1) + '. ' + (r.title || '') + '\n';
    compiled += '   URL: ' + (r.url || '') + '\n';
    compiled += '   ' + (r.text || '').slice(0, 600) + '\n\n';
  });
  compiled += '\n';
});

return { compiled: compiled.slice(0, 30000), keywordCount: keywords.length };

const d = $.steps.compileResearch.output;
const keywords = $.steps.parseKeywords.output.keywords;
const targetSite = $.input.targetWebsite || '';
const market = $.input.market || 'US';

let prompt = 'You are an expert SEO analyst. Analyze the following keyword research data and provide comprehensive SEO insights for each keyword.\n\n';
prompt += 'KEYWORDS: ' + keywords.join(', ') + '\n';
prompt += 'TARGET MARKET: ' + market + '\n';
if (targetSite) prompt += 'TARGET WEBSITE: ' + targetSite + '\n';
prompt += '\nSEARCH RESULTS ANALYSIS:\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Estimate relative search volume for each keyword (high/medium/low) based on content density\n';
prompt += '- Assess keyword difficulty based on competitor strength in results\n';
prompt += '- Identify search intent: informational, commercial, transactional, navigational\n';
prompt += '- Suggest related long-tail keywords\n';
prompt += '- Recommend content type that would rank well\n';
prompt += '- Prioritize keywords by opportunity score\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "keywords": [\n';
prompt += '    {\n';
prompt += '      "keyword": "the keyword",\n';
prompt += '      "estimatedVolume": "high|medium|low",\n';
prompt += '      "difficulty": "easy|medium|hard|very-hard",\n';
prompt += '      "searchIntent": "informational|commercial|transactional|navigational",\n';
prompt += '      "opportunityScore": 8,\n';
prompt += '      "topCompetitors": ["domain1.com", "domain2.com"],\n';
prompt += '      "relatedLongTail": ["long tail keyword 1", "long tail keyword 2"],\n';
prompt += '      "recommendedContentType": "blog post|landing page|guide|comparison",\n';
prompt += '      "notes": "strategic notes"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "overallStrategy": "SEO strategy recommendation based on the keyword portfolio",\n';
prompt += '  "quickWins": ["easiest keywords to rank for first"],\n';
prompt += '  "longTermTargets": ["high-value keywords that need more effort"],\n';
prompt += '  "contentPlan": [{ "keyword": "kw", "contentTitle": "suggested title", "priority": 1 }]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { keywords: [], overallStrategy: raw, quickWins: [], longTermTargets: [], contentPlan: [] }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Keyword', 'Est. Volume', 'Difficulty', 'Intent', 'Opportunity Score', 'Top Competitors', 'Long-Tail Keywords', 'Recommended Content', 'Notes']);
(ai.keywords || []).forEach(k => {
  rows.push([today, k.keyword || '', k.estimatedVolume || '', k.difficulty || '', k.searchIntent || '', String(k.opportunityScore || ''), (k.topCompetitors || []).join(', '), (k.relatedLongTail || []).join(', '), k.recommendedContentType || '', k.notes || '']);
});
return { rows, keywordCount: rows.length - 1 };

const ai = $.steps.parseAI.output;
const kws = ai.keywords || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'SEO Keyword Research Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Keywords Analyzed:* ' + kws.length + ' | *Market:* ' + ($.input.market || 'US') } });
blocks.push({ type: 'divider' });

if (ai.overallStrategy) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Strategy:* ' + ai.overallStrategy.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

kws.sort((a, b) => (b.opportunityScore || 0) - (a.opportunityScore || 0));
kws.slice(0, 8).forEach(k => {
  const scoreIcon = (k.opportunityScore || 0) >= 8 ? ':star:' : (k.opportunityScore || 0) >= 6 ? ':chart_with_upwards_trend:' : ':seedling:';
  const diffIcon = k.difficulty === 'easy' ? ':large_green_circle:' : k.difficulty === 'medium' ? ':large_yellow_circle:' : ':red_circle:';
  let text = scoreIcon + ' *' + k.keyword + '* (Score: ' + (k.opportunityScore || 'N/A') + ')\n';
  text += 'Volume: ' + (k.estimatedVolume || '?') + ' | ' + diffIcon + ' Difficulty: ' + (k.difficulty || '?') + ' | Intent: ' + (k.searchIntent || '?') + '\n';
  if (k.relatedLongTail && k.relatedLongTail.length > 0) text += '_Related:_ ' + k.relatedLongTail.slice(0, 3).join(', ');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

if (ai.quickWins && ai.quickWins.length > 0) {
  blocks.push({ type: 'divider' });
  let qwText = '*Quick Wins:*\n';
  ai.quickWins.forEach((q, i) => { qwText += ':zap: ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: qwText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Report saved to Google Sheets | Powered by Exa + Claude AI' }] });
const fallback = 'SEO Report: ' + kws.length + ' keywords analyzed';
return { blocks, fallback };
